export async function addShowToList(
  listId: string,
  show: {
    tmdb_id: number;
    title: string;
    poster_path: string | null;
    first_air_date?: string;
    overview?: string;
  },
) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");

  // Upsert show in shows table
  let { data: existingShow } = await supabase
    .from("shows")
    .select("id")
    .eq("tmdb_id", show.tmdb_id)
    .single();

  if (!existingShow) {
    const { data: newShow, error: showError } = await supabase
      .from("shows")
      .insert({
        tmdb_id: show.tmdb_id,
        title: show.title,
        poster_path: show.poster_path,
        first_air_date: show.first_air_date || null,
        overview: show.overview || null,
      })
      .select()
      .single();

    if (showError) throw new Error(showError.message);
    existingShow = newShow;
  }

  // Get max position in list
  const { data: items } = await supabase
    .from("list_items")
    .select("position")
    .eq("list_id", listId)
    .order("position", { ascending: false })
    .limit(1);

  const nextPosition = (items?.[0]?.position ?? -1) + 1;

  const { error } = await supabase.from("list_items").insert({
    list_id: listId,
    show_id: existingShow!.id,
    position: nextPosition,
  });

  if (error) throw new Error(error.message);

  revalidatePath(`/lists/${listId}`);
}

export async function removeShowFromList(listId: string, itemId: string) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");

  const { error } = await supabase.from("list_items").delete().eq("id", itemId);

  if (error) throw new Error(error.message);

  revalidatePath(`/lists/${listId}`);
}

export async function updateShowRating(
  listId: string,
  itemId: string,
  rating: number,
) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");

  if (rating < 1 || rating > 10) throw new Error("Rating must be 1-10");

  const { error } = await supabase
    .from("list_items")
    .update({ rating })
    .eq("id", itemId);

  if (error) throw new Error(error.message);

  revalidatePath(`/lists/${listId}`);
}

export async function reorderListItems(listId: string, itemIds: string[]) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");

  // Update positions
  const updates = itemIds.map((id, index) =>
    supabase.from("list_items").update({ position: index }).eq("id", id),
  );

  await Promise.all(updates);

  revalidatePath(`/lists/${listId}`);
}

export async function importFromJson(jsonData: unknown) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");
  console.log("quauaaaa");

  const { parseTraktJson } = await import("@/lib/import/trakt-parser");
  const parsed = parseTraktJson(jsonData);

  // Create the list
  const { data: lists } = await supabase
    .from("lists")
    .select("position")
    .eq("user_id", user.id)
    .order("position", { ascending: false })
    .limit(1);

  const nextPosition = (lists?.[0]?.position ?? -1) + 1;

  const { data: list, error: listError } = await supabase
    .from("lists")
    .insert({
      user_id: user.id,
      name: parsed.name,
      description: parsed.description || null,
      is_public: parsed.is_public,
      position: nextPosition,
    })
    .select()
    .single();

  if (listError) throw new Error(listError.message);

  // For each show, look up TMDB data and insert
  let position = 0;
  console.log("hie", parsed);
  for (const show of parsed.shows) {
    try {
      // Try IMDB ID lookup first, then fall back to title search
      let foundShow: {
        tmdb_id: number;
        title: string;
        poster_path: string | null;
        first_air_date: string | null;
        overview: string | null;
      } | null = null;

      if (show.imdb_id) {
        const result = await findByImdbId(show.imdb_id);
        console.log(result);
        if (result) {
          foundShow = {
            tmdb_id: result.id,
            title: result.name,
            poster_path: result.poster_path,
            first_air_date: result.first_air_date || null,
            overview: result.overview || null,
          };
        }
      }

      if (!foundShow) {
        const data = await searchShows(show.title);
        const first = data.results?.[0];
        if (first) {
          foundShow = {
            tmdb_id: first.id,
            title: first.name,
            poster_path: first.poster_path,
            first_air_date: first.first_air_date || null,
            overview: first.overview || null,
          };
        }
      }

      if (foundShow?.tmdb_id) {
        const tmdbShow = foundShow;
        // Upsert show
        let { data: existingShow } = await supabase
          .from("shows")
          .select("id")
          .eq("tmdb_id", tmdbShow.tmdb_id)
          .single();

        if (!existingShow) {
          const { data: newShow } = await supabase
            .from("shows")
            .insert({
              tmdb_id: tmdbShow.tmdb_id,
              imdb_id: show.imdb_id,
              title: tmdbShow.title || show.title,
              poster_path: tmdbShow.poster_path,
              first_air_date: tmdbShow.first_air_date || null,
              overview: tmdbShow.overview || null,
            })
            .select()
            .single();

          existingShow = newShow;
        }

        if (existingShow) {
          await supabase.from("list_items").insert({
            list_id: list.id,
            show_id: existingShow.id,
            position,
          });
          position++;
        }
      }
    } catch (e) {
      console.error(`Failed to import show: ${show.title}`, e);
      // Continue with next show
    }
  }

  revalidatePath("/lists");
  return { listId: list.id, importedCount: position };
}
