"use client";

import Image from "next/image";
import { getPosterUrl } from "@/lib/tmdb/client";
import { Television } from "@phosphor-icons/react";

type ShowCardProps = {
  title: string;
  posterPath: string | null;
  rating?: number | null;
  position?: number;
  onRatingChange?: (rating: number) => void;
  compact?: boolean;
};

export function ShowCard({
  title,
  posterPath,
  rating,
  position,
  onRatingChange,
  compact = false,
}: ShowCardProps) {
  const posterUrl = getPosterUrl(posterPath, compact ? "w185" : "w342");

  return (
    <div className="group relative overflow-hidden rounded-[var(--radius-lg)] border border-border bg-bg-surface transition-colors hover:border-border-hover">
      {/* Position badge */}
      {position !== undefined && (
        <div className="absolute top-2 left-2 z-10 flex h-6 w-6 items-center justify-center rounded-[var(--radius-sm)] bg-bg-primary/80 text-xs font-mono font-bold text-text-primary tabular-nums backdrop-blur-sm">
          {position}
        </div>
      )}

      {/* Poster */}
      <div
        className={`relative w-full ${compact ? "aspect-[2/3]" : "aspect-[2/3]"} bg-bg-elevated`}
      >
        {posterUrl ? (
          <Image
            src={posterUrl}
            alt={title}
            fill
            className="object-cover"
            sizes={compact ? "120px" : "200px"}
          />
        ) : (
          <div className="flex h-full items-center justify-center">
            <Television size={32} className="text-text-faint" />
          </div>
        )}

        {/* Rating overlay on hover */}
        {onRatingChange && (
          <div className="absolute inset-0 flex items-end bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 transition-opacity group-hover:opacity-100">
            <RatingBar
              value={rating ?? null}
              onChange={onRatingChange}
              className="w-full p-2"
            />
          </div>
        )}
      </div>

      {/* Info */}
      <div className="p-3">
        <p className="truncate text-sm font-medium text-text-primary">
          {title}
        </p>
        {rating && (
          <p className="mt-1 font-mono text-xs text-accent tabular-nums">
            {rating}/10
          </p>
        )}
      </div>
    </div>
  );
}

type RatingBarProps = {
  value: number | null;
  onChange: (rating: number) => void;
  className?: string;
};

function RatingBar({ value, onChange, className = "" }: RatingBarProps) {
  return (
    <div className={`flex gap-0.5 ${className}`}>
      {Array.from({ length: 10 }, (_, i) => i + 1).map((n) => (
        <button
          key={n}
          onClick={(e) => {
            e.stopPropagation();
            onChange(n);
          }}
          className={`h-2 flex-1 rounded-sm transition-colors ${
            value && n <= value
              ? "bg-accent"
              : "bg-text-faint/30 hover:bg-text-faint/60"
          }`}
          aria-label={`Rate ${n}`}
        />
      ))}
    </div>
  );
}

export { RatingBar };
